from typing import List

class Solution:
    def countValidPlans(self, timestamps: List[int], minInterval: int) -> int:
        ts = sorted(timestamps)  # 排序后按 mask 位取元素
        n = len(ts)
        ans = 0
        for mask in range(1 << n):  # 枚举所有子集，含空集
            picked = [ts[i] for i in range(n) if mask & (1 << i)]
            ok = True
            for i in range(len(picked)):
                for j in range(i + 1, len(picked)):
                    if picked[j] - picked[i] < minInterval:  # 任意一对都要满足间隔
                        ok = False
                        break
                if not ok:
                    break
            if ok:
                ans += 1
        return ans
```
```java
public class Solution {
    public int countValidPlans(int[] timestamps, int minInterval) {
        int[] ts = timestamps.clone();
        java.util.Arrays.sort(ts);
        int n = ts.length, ans = 0;
        for (int mask = 0; mask < (1 << n); mask++) {
            java.util.ArrayList<Integer> picked = new java.util.ArrayList<>();
            for (int i = 0; i < n; i++)
                if ((mask & (1 << i)) != 0) picked.add(ts[i]);
            boolean ok = true;
            for (int i = 0; i < picked.size() && ok; i++)
                for (int j = i + 1; j < picked.size(); j++)
                    if (picked.get(j) - picked.get(i) < minInterval) ok = false;
            if (ok) ans++;
        }
        return ans;
    }
}
