using namespace std;

class Solution {
 public:
  int countValidPlans(vector<int>& timestamps, int minInterval) {
    vector<int> ts = timestamps;
    sort(ts.begin(), ts.end());  // 排序后按 mask 位取元素
    int n = (int)ts.size(), ans = 0;
    for (int mask = 0; mask < (1 << n); mask++) {  // 枚举所有子集，含空集
      vector<int> picked;
      for (int i = 0; i < n; i++)
        if (mask & (1 << i)) picked.push_back(ts[i]);
      bool ok = true;
      for (int i = 0; i < (int)picked.size() && ok; i++)
        for (int j = i + 1; j < (int)picked.size(); j++)
          if (picked[j] - picked[i] < minInterval) ok = false;  // 任意一对都要满足间隔
      if (ok) ans++;
    }
    return ans;
  }
};
